<template><q-page padding><OutletHeaderPanel :title="visit?.Code || 'Outlet Visit'" :subtitle="visit ? outletLabel(visit.OutletCode) : ''" class="q-mb-md"><template #side><OutletProgressChip :progress="visit?.Status"/></template></OutletHeaderPanel><q-card v-if="visit"><q-card-section><div class="row q-col-gutter-md"><div class="col-6">Date: {{ visit.Date }}</div><div class="col-6">Status: {{ visit.Status }}</div><div class="col-12">Planning Comment: {{ visit.StatusPlannedComment }}</div><div class="col-12">Completed Comment: {{ visit.StatusCompletedComment }}</div><div class="col-12">Postponed Comment: {{ visit.StatusPostponedComment }}</div><div class="col-12">Cancelled Comment: {{ visit.StatusCancelledComment }}</div></div></q-card-section></q-card><div v-if="visit?.Status === 'PLANNED'" class="row justify-end q-gutter-sm q-mt-md"><q-btn color="positive" label="Complete" :loading="saving" @click="openCompleteDialog"/><q-btn color="warning" label="Postpone" :loading="saving" @click="openPostponeDialog"/><q-btn color="negative" label="Cancel" :loading="saving" @click="openCancelDialog"/></div><q-dialog v-model="completeDialog"><q-card style="min-width: 320px"><q-card-section><div class="text-h6">Complete Visit</div></q-card-section><q-card-section><q-input v-model="completeForm.notes" label="Notes (optional)" outlined autogrow/></q-card-section><q-card-actions align="right"><q-btn v-close-popup flat label="Cancel"/><q-btn color="positive" label="Complete" :loading="saving" @click="submitComplete"/></q-card-actions></q-card></q-dialog><q-dialog v-model="postponeDialog"><q-card style="min-width: 320px"><q-card-section><div class="text-h6">Postpone Visit</div></q-card-section><q-card-section class="q-gutter-md"><q-input v-model="postponeForm.reason" label="Reason" outlined autogrow/><q-input v-model="postponeForm.date" label="Next Visit Date" outlined readonly><template #append><q-icon name="event" class="cursor-pointer"><q-popup-proxy cover transition-show="scale" transition-hide="scale"><q-date v-model="postponeForm.date" mask="YYYY-MM-DD"><div class="row items-center justify-end"><q-btn v-close-popup label="Close" color="primary" flat/></div></q-date></q-popup-proxy></q-icon></template></q-input></q-card-section><q-card-actions align="right"><q-btn v-close-popup flat label="Cancel"/><q-btn color="warning" label="Postpone" :loading="saving" @click="submitPostpone"/></q-card-actions></q-card></q-dialog><q-dialog v-model="cancelDialog"><q-card style="min-width: 320px"><q-card-section><div class="text-h6">Cancel Visit</div></q-card-section><q-card-section class="q-gutter-md"><q-input v-model="cancelForm.reason" label="Reason" outlined autogrow/><q-input v-model="cancelForm.date" label="Next Visit Date (optional)" outlined readonly clearable><template #append><q-icon name="event" class="cursor-pointer"><q-popup-proxy cover transition-show="scale" transition-hide="scale"><q-date v-model="cancelForm.date" mask="YYYY-MM-DD"><div class="row items-center justify-end"><q-btn v-close-popup label="Close" color="primary" flat/></div></q-date></q-popup-proxy></q-icon></template></q-input></q-card-section><q-card-actions align="right"><q-btn v-close-popup flat label="Cancel"/><q-btn color="negative" label="Cancel Visit" :loading="saving" @click="submitCancel"/></q-card-actions></q-card></q-dialog></q-page></template>
<script setup>
import { computed, onMounted, ref } from 'vue'; import { useRoute } from 'vue-router'; import { useOutletVisits } from '../../../composables/operations/outlets/useOutletVisits.js'; import OutletHeaderPanel from '../../../components/Operations/Outlets/OutletHeaderPanel.vue'; import OutletProgressChip from '../../../components/Operations/Outlets/OutletProgressChip.vue'
defineOptions({ name: 'OutletVisitsViewPage' }); const route = useRoute(); const flow = useOutletVisits(); const { saving, reload, getVisit, outletLabel, completeVisit, postponeVisit, cancelVisit } = flow; const visit = computed(() => getVisit(route.params.code)); const completeDialog = ref(false); const postponeDialog = ref(false); const cancelDialog = ref(false); const completeForm = ref({ notes: '' }); const postponeForm = ref({ reason: '', date: '' }); const cancelForm = ref({ reason: '', date: '' }); function openCompleteDialog() { completeForm.value = { notes: '' }; completeDialog.value = true } function openPostponeDialog() { postponeForm.value = { reason: '', date: '' }; postponeDialog.value = true } function openCancelDialog() { cancelForm.value = { reason: '', date: '' }; cancelDialog.value = true } async function submitComplete() { if (!visit.value) return; const completed = await completeVisit(visit.value, { StatusCompletedComment: completeForm.value.notes }); if (completed) completeDialog.value = false } async function submitPostpone() { if (!visit.value) return; const postponed = await postponeVisit(visit.value, { StatusPostponedComment: postponeForm.value.reason, Date: postponeForm.value.date }); if (postponed) postponeDialog.value = false } async function submitCancel() { if (!visit.value) return; const cancelled = await cancelVisit(visit.value, { StatusCancelledComment: cancelForm.value.reason, Date: cancelForm.value.date }); if (cancelled) cancelDialog.value = false } onMounted(() => reload())
</script>
